import { Component, Element, h, Host, Prop } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';
import { ActionableListItemConfig } from '../wdpr-actionable-list-item/wdpr-actionable-list-item.model';

@Component({
  tag: 'wdpr-actionable-list',
  shadow: true,
})
export class WdprActionableList {
  @Element() el: HTMLElement;

  @Prop() items: ActionableListItemConfig[] = [];

  @Prop() showDivider: boolean = true;

  private _renderListItem(item: ActionableListItemConfig, index: number, totalItems: number) {
    const shouldShowDivider = this.showDivider && index < totalItems - 1;

    return (
      <div key={item.id}>
        <wdpr-actionable-list-item
          itemId={item.id}
          headerLabel={item.headerLabel}
          preHeader={item.preHeader}
          subtextLabel={item.subtextLabel}
          headerLeadingIcon={item.headerLeadingIcon}
          headerSize={item.headerSize}
          linkLeadingIcon={item.linkLeadingIcon}
          linkText={item.linkText}
          linkTrailingIcon={item.linkTrailingIcon}
          linkVariant={item.linkVariant}
          linkHref={item.linkHref}
          linkTarget={item.linkTarget}
          linkA11yLabel={item.linkA11yLabel}
          linkDisabled={item.linkDisabled}
          linkRel={item.linkRel}>
        </wdpr-actionable-list-item>
        {shouldShowDivider && (
          <div class="my-4">
            <wdpr-divider />
          </div>
        )}
      </div>
    );
  }

  private _renderItems() {
    const totalItems = this.items.length;

    return (
      <div class={customTwMerge('flex flex-col')}>
        {this.items.map((item, index) =>
          this._renderListItem(item, index, totalItems)
        )}
      </div>
    );
  }

  render() {
    return (
      <Host>
        {this._renderItems()}
      </Host>
    );
  }
}
